// Get data from both previous nodes
const knownData = $node["Your Known Data"].json;
const pdlResponse = $input.first().json;

// PDL nests person data under 'data'
const person = pdlResponse.data || pdlResponse;

// Helper: safely get a string value (PDL returns booleans for gated fields)
function safeStr(val) {
  if (typeof val === 'string' && val.length > 0) return val;
  return null;
}

// Extract fetched profile data from PDL response
const fetched_name = safeStr(person.full_name) || safeStr(person.name) || 'Not found';
const fetched_position = safeStr(person.job_title) || 'Not found';
const fetched_company = safeStr(person.job_company_name) || 'Not found';
const fetched_location = safeStr(person.location_name)
  || safeStr(person.job_company_location_name)
  || safeStr(person.location_country)
  || 'Not found';
const fetched_industry = safeStr(person.industry) || safeStr(person.job_company_industry) || 'Not found';

// Helper: compare two strings (case-insensitive, partial match)
function compare(known, fetched) {
  if (!known || !fetched || fetched === 'Not found') {
    return { match: false, note: 'Data missing' };
  }
  const k = known.toLowerCase().trim();
  const f = fetched.toLowerCase().trim();
  if (k === f) {
    return { match: true, note: 'Exact match' };
  }
  if (f.includes(k) || k.includes(f)) {
    return { match: true, note: 'Partial match' };
  }
  return { match: false, note: 'Different' };
}

// Run comparisons
const nameCheck = compare(knownData.known_name, fetched_name);
const positionCheck = compare(knownData.known_position, fetched_position);
const companyCheck = compare(knownData.known_company, fetched_company);
const locationCheck = compare(knownData.known_location, fetched_location);
const industryCheck = compare(knownData.known_industry, fetched_industry);

// Count matches
const fields = [nameCheck, positionCheck, companyCheck, locationCheck, industryCheck];
const matchCount = fields.filter(f => f.match).length;
const hasChanges = fields.some(f => !f.match);

return [
  {
    json: {
      summary: `${matchCount} of 5 fields match`,
      linkedin_url: knownData.linkedin_url,
      has_changes: hasChanges,
      comparison: {
        name: {
          known: knownData.known_name,
          fetched: fetched_name,
          result: nameCheck.note
        },
        position: {
          known: knownData.known_position,
          fetched: fetched_position,
          result: positionCheck.note
        },
        company: {
          known: knownData.known_company,
          fetched: fetched_company,
          result: companyCheck.note
        },
        location: {
          known: knownData.known_location,
          fetched: fetched_location,
          result: locationCheck.note
        },
        industry: {
          known: knownData.known_industry,
          fetched: fetched_industry,
          result: industryCheck.note
        }
      },
      match_count: matchCount,
      total_fields: 5
    }
  }
];

const data = $input.first().json;
const changes = [];

// Collect all fields that don't match
for (const [field, details] of Object.entries(data.comparison)) {
  if (details.result !== 'Exact match') {
    changes.push({
      field: field.charAt(0).toUpperCase() + field.slice(1),
      known: details.known,
      fetched: details.fetched,
      status: details.result
    });
  }
}

return [{
  json: {
    linkedin_url: data.linkedin_url,
    summary: data.summary,
    changes_detected: changes.length,
    changed_fields: changes
  }
}];
